var updateUserProfileRequestParser = aip.MustNewUpdateRequestParser[*v11.UpdateUserProfileRequest, *v13.UserProfile]()

func (s *userService_UserProfileServer) UpdateUserProfile(ctx context.Context, request *v11.UpdateUserProfileRequest) (*v13.UserProfile, error) {
	for {
		response, err := s.updateUserProfile(ctx, request)
		if err != nil {
			if request.GetUserProfile().GetEtag() == "" && status.HasCode(err, codes.Aborted) {
				// Request did not specify an ETag => we retry.
				// In order to understand why we still use ETag in the db layer, consider the following situation:
				//  > `resource.metadata` is stored as JSONB in the store.
				//  > Request A wants to update `resource.metadata.field1` and does not care about ETag.
				//  > Request B wants to update `resource.metadata.field2` and does not care about ETag.
				//  > Request A reads the resource and patches it.
				//  > Request B reads the resource and patches it.
				//  > Request A persists the patched resource, followed by Request B.
				//  > Request A's changes are lost.
				select {
				case <-ctx.Done():
					return nil, status.Errorf(codes.Canceled, "context canceled while retrying update").Err()
				default:
					continue
				}
			}
			return nil, err
		}
		return response, nil
	}
}

func (s *userService_UserProfileServer) updateUserProfile(ctx context.Context, request *v11.UpdateUserProfileRequest) (*v13.UserProfile, error) {
	if len(request.GetUpdateMask().GetPaths()) == 0 {
		return nil, status.Errorf(codes.InvalidArgument, "missing update_mask.paths").Err()
	}
	if resourcename.ContainsWildcard(request.UserProfile.Name) {
		return nil, status.Errorf(codes.InvalidArgument, "cannot use wildcard").Err()
	}

	// STEP 1: Parse request.
	parsedRequest, err := updateUserProfileRequestParser.Parse(request)
	if err != nil {
		return nil, status.Errorf(codes.InvalidArgument, "parsing request: %v", err).Err()
	}

	// STEP 2: retrieve existing resource.
	getUserProfileRequest := &v11.GetUserProfileRequest{Name: request.UserProfile.Name}
	existingUserProfile, err := s.GetUserProfile(ctx, getUserProfileRequest)
	if err != nil {
		return nil, err
	}
	// Verify that the resource is not soft deleted
	if existingUserProfile.DeleteTime != nil {
		return nil, status.Errorf(codes.NotFound, "userProfile does not exist").Err()
	}
	// Capture the Etag. If it is not set, use the latest available Etag.
	etag := request.GetUserProfile().GetEtag()
	if etag == "" {
		etag = existingUserProfile.GetEtag()
	}

	// STEP 3: Patch the existing resource.
	patchedUserProfile := proto.CloneOf(existingUserProfile)
	parsedRequest.ApplyFieldMask(patchedUserProfile, request.UserProfile)
	if err := protovalidate.Validate(patchedUserProfile); err != nil {
		return nil, status.Errorf(codes.InvalidArgument, "validating patched resource: %v", err).Err()
	}

	// Set the update time.
	patchedUserProfile.UpdateTime = timestamppb.Now()
	{ // Compute the new Etag.
		var err error
		patchedUserProfile.Etag, err = aip.ComputeETag(patchedUserProfile)
		if err != nil {
			return nil, status.Errorf(codes.Internal, "computing new etag: %v", err).Err()
		}
	}

	// STEP 4: Insert patched resource.
	userProfileModel, err := model.UserProfileFromPb(patchedUserProfile)
	if err != nil {
		return nil, status.Errorf(codes.Internal, "converting userProfile from pb to model: %v", err).Err()
	}
	dbUserProfileModel, err := s.store.UpdateUserProfile(ctx, userProfileModel, parsedRequest.GetSQLUpdateClause(), parsedRequest.GetSQLColumns(), etag)
	if err != nil {
		if errors.Is(err, model.ErrUserProfileNotExist) {
			return nil, status.Errorf(codes.NotFound, "userProfile does not exist").Err()
		}
		if errors.Is(err, model.ErrUserProfileETagChanged) {
			return nil, status.Errorf(codes.Aborted, "ETag changed").Err()
		}
		return nil, status.FromError(err, "updating userProfile").Err()
	}

	userProfile, err := dbUserProfileModel.ToPb()
	if err != nil {
		return nil, status.Errorf(codes.Internal, "converting userProfile from model to pb: %v", err).Err()
	}

	return userProfile, nil
}

